def cmd_setup_hooks(args):
    """Install/uninstall Kindex hooks in Claude Code's settings.json."""
    from .setup import install_claude_hooks
    cfg = _config(args)
    dry_run = getattr(args, "dry_run", False)

    if getattr(args, "uninstall", False):
        # Remove hooks by loading settings and filtering out kindex entries
        settings_path = cfg.claude_path / "settings.json"
        if settings_path.exists():
            import json as _json
            data = _json.loads(settings_path.read_text())
            hooks = data.get("hooks", {})
            changed = False
            for key in ["SessionStart", "PreCompact"]:
                if key in hooks:
                    before = len(hooks[key])
                    hooks[key] = [
                        h for h in hooks[key]
                        if "kin prime" not in str(h)
                        and "compact-hook" not in str(h)
                        and "kindex" not in str(h).lower()
                    ]
                    if len(hooks[key]) < before:
                        changed = True
                        print(f"Removed Kindex {key} hook")
            if changed and not dry_run:
                settings_path.write_text(_json.dumps(data, indent=2) + "\n")
                print(f"Updated {settings_path}")
            elif not changed:
                print("No Kindex hooks found to remove")
        else:
            print("No Claude Code settings.json found")
        return

    actions = install_claude_hooks(cfg, dry_run=dry_run)
    for a in actions:
        print(f"  {a}")

def cmd_setup_cron(args):
    """Install/uninstall periodic cron job for kin maintenance."""
    import platform
    cfg = _config(args)
    dry_run = getattr(args, "dry_run", False)
    method = getattr(args, "method", None)

    # Auto-detect method
    if method is None:
        method = "launchd" if platform.system() == "Darwin" else "crontab"

    if getattr(args, "uninstall", False):
        if method == "launchd":
            from .setup import uninstall_launchd
            actions = uninstall_launchd(dry_run=dry_run)
        else:
            # Remove crontab entry
            import subprocess
            result = subprocess.run(["crontab", "-l"], capture_output=True, text=True)
            if result.returncode == 0:
                lines = result.stdout.splitlines()
                filtered = [l for l in lines if "kin cron" not in l and "kindex" not in l]
                if len(filtered) < len(lines):
                    if not dry_run:
                        new_crontab = "\n".join(filtered) + "\n"
                        subprocess.run(["crontab", "-"], input=new_crontab,
                                       capture_output=True, text=True)
                    actions = ["Removed crontab entry"]
                else:
                    actions = ["No crontab entry found"]
            else:
                actions = ["No crontab found"]
    else:
        if method == "launchd":
            from .setup import install_launchd
            actions = install_launchd(cfg, dry_run=dry_run)
        else:
            from .setup import install_crontab
            actions = install_crontab(cfg, dry_run=dry_run)

    for a in actions:
        print(f"  {a}")

def _dotget(d: dict, key: str):
    """Get a value from a nested dict via dot-separated key."""
    parts = key.split(".")
    current = d
    for part in parts:
        if isinstance(current, dict) and part in current:
            current = current[part]
        else:
            return None
    return current

def _dotset(d: dict, key: str, value) -> None:
    """Set a value in a nested dict via dot-separated key."""
    parts = key.split(".")
    current = d
    for part in parts[:-1]:
        if part not in current or not isinstance(current[part], dict):
            current[part] = {}
        current = current[part]
    current[parts[-1]] = value

def _coerce_value(value: str):
    """Coerce a string value to the appropriate Python type."""
    if value.lower() in ("true", "yes"):
        return True
    if value.lower() in ("false", "no"):
        return False
    try:
        return int(value)
    except ValueError:
        pass
    try:
        return float(value)
    except ValueError:
        pass
    # List syntax: [a, b, c]
    if value.startswith("[") and value.endswith("]"):
        items = [s.strip().strip("'\"") for s in value[1:-1].split(",")]
        return [i for i in items if i]
    return value

def _config_write(key: str, value: str, config_path: str | None = None,
                   global_: bool = False) -> None:
    """Write a config value to the appropriate config file.

    Resolution (like git config):
    - --config <path>:  explicit file
    - --global:         user-level (~/.config/kindex/kin.yaml)
    - default:          local file if one exists in cwd, else global
    """
    import yaml

    if config_path:
        path = Path(config_path).expanduser().resolve()
    elif global_:
        from .config import _GLOBAL_PATHS
        path = None
        for p in _GLOBAL_PATHS:
            p = p.expanduser().resolve()
            if p.exists():
                path = p
                break
        if path is None:
            path = Path.home() / ".config" / "kindex" / "kin.yaml"
            path.parent.mkdir(parents=True, exist_ok=True)
    else:
        from .config import _LOCAL_PATHS, _GLOBAL_PATHS
        path = None
        for p in _LOCAL_PATHS:
            p = p.expanduser().resolve()
            if p.exists():
                path = p
                break
        if path is None:
            for p in _GLOBAL_PATHS:
                p = p.expanduser().resolve()
                if p.exists():
                    path = p
                    break
        if path is None:
            path = Path.home() / ".config" / "kindex" / "kin.yaml"
            path.parent.mkdir(parents=True, exist_ok=True)

    # Load existing or start fresh
    if path.exists():
        data = yaml.safe_load(path.read_text()) or {}
    else:
        data = {}

    _dotset(data, key, _coerce_value(value))
    path.write_text(yaml.dump(data, default_flow_style=False, sort_keys=False))

def main():
    parser = build_parser()
    args = parser.parse_args()

    if args.version:
        print(f"kin {__version__} (Kindex)")
        return

    if not args.command:
        parser.print_help()
        return

    if hasattr(args, "func"):
        args.func(args)
    else:
        parser.print_help()

def _detect_user() -> str:
    """Auto-detect user identity from git config or OS username."""
    import subprocess
    # Try git config
    try:
        result = subprocess.run(
            ["git", "config", "--global", "user.name"],
            capture_output=True, text=True, timeout=2,
        )
        if result.returncode == 0 and result.stdout.strip():
            return result.stdout.strip().lower().replace(" ", "-")
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    # Fall back to OS username
    return os.environ.get("USER", os.environ.get("USERNAME", "unknown"))

def _deep_merge(base: dict, override: dict) -> dict:
    """Recursively merge override into base (override wins)."""
    merged = dict(base)
    for key, val in override.items():
        if key in merged and isinstance(merged[key], dict) and isinstance(val, dict):
            merged[key] = _deep_merge(merged[key], val)
        else:
            merged[key] = val
    return merged

def load_config(config_path: str | Path | None = None) -> Config:
    """Load config with layered merging: code defaults → global → local.

    Like git config: global (~/.config/kindex/kin.yaml) is loaded first,
    then local (.kin / kin.yaml / conv.yaml in cwd) merges over it.
    An explicit config_path bypasses layering and loads only that file.
    """
    if config_path:
        p = Path(config_path).expanduser().resolve()
        if p.exists():
            data = yaml.safe_load(p.read_text()) or {}
            return Config(**data)
        return Config()

    # Layer 1: global config (user-level)
    merged: dict = {}
    for p in _GLOBAL_PATHS:
        p = p.expanduser().resolve()
        if p.exists():
            data = yaml.safe_load(p.read_text()) or {}
            merged = _deep_merge(merged, data)
            break  # use first global found

    # Layer 2: local config (project-level) merges over global
    for p in _LOCAL_PATHS:
        p = p.expanduser().resolve()
        if p.exists():
            data = yaml.safe_load(p.read_text()) or {}
            merged = _deep_merge(merged, data)
            break  # use first local found

    return Config(**merged) if merged else Config()

def current_user(self) -> str:
    """Resolve current user identity. Config > git > OS."""
    if self.user:
        return self.user
    return _detect_user()

def _check_watches(store: "Store", verbose: bool = False) -> dict:
    """Check watch nodes for expiry and flag triggered ones.

    - Expired watches (past their expires date) get archived.
    - Watches with check_command in extra get flagged for Claude attention.
    """
    import datetime as _dt

    results = {"expired": 0, "notified": 0}

    try:
        # Query all active watch nodes (including those past expiry that
        # haven't been archived yet — active_watches() filters those out)
        watches = store.all_nodes(node_type="watch", status="active", limit=200)
    except Exception:
        return results

    today = _dt.date.today().isoformat()

    for w in watches:
        extra = w.get("extra") or {}
        expires = extra.get("expires", "")
        wid = w["id"]

        # Expire overdue watches
        if expires and expires < today:
            store.update_node(wid, status="archived")
            results["expired"] += 1
            if verbose:
                print(f"  Expired watch: {w['title']} (was due {expires})")
            continue

        # Boost weight of watches approaching expiry (within 3 days)
        if expires:
            try:
                exp_date = _dt.date.fromisoformat(expires)
                days_left = (exp_date - _dt.date.today()).days
                if 0 <= days_left <= 3:
                    # Boost so it surfaces prominently in prime_context
                    current_weight = w.get("weight", 0.5)
                    if current_weight < 0.8:
                        store.update_node(wid, weight=0.9)
                        results["notified"] += 1
                        if verbose:
                            print(f"  Boosted watch: {w['title']} ({days_left}d left)")
            except (ValueError, TypeError):
                pass

    return results

def _check_reminders(config: "Config", store: "Store", verbose: bool = False) -> dict:
    """Run the reminder check cycle."""
    if not config.reminders.enabled:
        return {"fired": 0, "auto_snoozed": 0}

    from .reminders import auto_snooze_stale, check_and_fire

    fired = check_and_fire(store, config)
    auto_snoozed = auto_snooze_stale(store, config)

    if verbose and fired:
        for r in fired:
            print(f"  Fired reminder: {r['title']}")

    return {"fired": len(fired), "auto_snoozed": auto_snoozed}

def find_new_sessions(config: "Config", since_iso: str) -> list[Path]:
    """Find JSONL session files modified since the given timestamp.

    Args:
        config: Kindex configuration.
        since_iso: ISO timestamp string. Files modified after this time
                   are returned.

    Returns:
        List of Path objects for new/modified JSONL files.
    """
    projects_dir = config.claude_path / "projects"
    if not projects_dir.exists():
        return []

    try:
        since_dt = datetime.datetime.fromisoformat(since_iso)
    except (ValueError, TypeError):
        # If invalid timestamp, return all files
        since_dt = datetime.datetime.min

    results = []
    for jsonl_path in projects_dir.rglob("*.jsonl"):
        try:
            mtime = datetime.datetime.fromtimestamp(jsonl_path.stat().st_mtime)
            if mtime > since_dt:
                results.append(jsonl_path)
        except OSError:
            continue

    return sorted(results, key=lambda p: p.stat().st_mtime, reverse=True)

def _extract_session_text_quick(jsonl_path: Path, max_chars: int = 4000) -> str:
    """Quick text extraction from a JSONL session file."""
    import json

    texts = []
    total_len = 0

    try:
        with open(jsonl_path, "r", errors="replace") as f:
            for line in f:
                if total_len >= max_chars:
                    break
                try:
                    entry = json.loads(line)
                except (json.JSONDecodeError, ValueError):
                    continue

                role = entry.get("role", "")
                if role != "assistant":
                    continue

                content = entry.get("content", "")
                if isinstance(content, str):
                    chunk = content[:800]
                    texts.append(chunk)
                    total_len += len(chunk)
                elif isinstance(content, list):
                    for block in content:
                        if isinstance(block, dict) and block.get("type") == "text":
                            chunk = block.get("text", "")[:800]
                            texts.append(chunk)
                            total_len += len(chunk)
    except OSError:
        return ""

    return "\n".join(texts)

def keyword_extract(text: str, existing_titles: list[str] | None = None) -> dict:
    """Keyword-based extraction when LLM unavailable.

    Extracts concepts (capitalized phrases, noun phrases, quoted terms),
    decisions, questions, connections, and bridge opportunities.
    """
    if existing_titles is None:
        existing_titles = []
    existing_lower = {t.lower(): t for t in existing_titles}

    concepts = []
    connections = []
    decisions = []
    questions = []
    bridge_opportunities = []
    seen = set()

    # ── Concept extraction ─────────────────────────────────────────────

    # 1. Capitalized multi-word phrases (proper nouns / concepts)
    phrases = re.findall(r'\b([A-Z][a-z]+(?:\s+[A-Z][a-z]+)+)\b', text)
    for phrase in phrases:
        lower = phrase.lower()
        if lower not in seen and len(phrase) > 5:
            seen.add(lower)
            concepts.append({
                "title": phrase,
                "content": "",
                "domains": [],
                "type": "concept",
            })

    # 2. Noun phrases: adjective+noun or noun+noun patterns (lowercase)
    noun_phrases = re.findall(
        r'\b([a-z]+(?:\s+[a-z]+){1,3})\s+(?:system|pattern|architecture|model|framework|'
        r'algorithm|method|approach|technique|protocol|strategy|mechanism|process|structure|'
        r'design|concept|principle|theory|analysis)\b',
        text, re.IGNORECASE,
    )
    for np_match in noun_phrases:
        # Reconstruct the full noun phrase with the head noun
        full_start = text.lower().find(np_match.lower())
        if full_start >= 0:
            # Find the head noun that follows
            after = text[full_start + len(np_match):].strip()
            head_match = re.match(
                r'(system|pattern|architecture|model|framework|algorithm|method|approach|'
                r'technique|protocol|strategy|mechanism|process|structure|design|concept|'
                r'principle|theory|analysis)\b', after, re.IGNORECASE)
            if head_match:
                full_phrase = f"{np_match} {head_match.group(1)}".strip()
                lower = full_phrase.lower()
                if lower not in seen and len(full_phrase) > 5:
                    seen.add(lower)
                    concepts.append({
                        "title": full_phrase,
                        "content": "",
                        "domains": [],
                        "type": "concept",
                    })

    # 3. Quoted terms
    quoted = re.findall(r'"([^"]{3,50})"', text)
    for q in quoted:
        lower = q.lower()
        if lower not in seen:
            seen.add(lower)
            concepts.append({
                "title": q,
                "content": "",
                "domains": [],
                "type": "concept",
            })

    # 4. "learned that ..." patterns
    learned_patterns = re.findall(
        r'(?:learned that|discovered that|found out that|realized that|'
        r'understood that|noticed that|need to investigate)\s+(.{10,100}?)(?:\.|$)',
        text, re.IGNORECASE,
    )
    for finding in learned_patterns:
        lower = finding.strip().lower()
        if lower not in seen:
            seen.add(lower)
            concepts.append({
                "title": finding.strip()[:60],
                "content": finding.strip(),
                "domains": [],
                "type": "concept",
            })

    # ── Decision extraction ────────────────────────────────────────────

    decision_patterns = re.findall(
        r'(?:decided to|chose to|went with|will use|choosing|opted for|'
        r'decision:\s*|decided that)\s+(.{5,120}?)(?:\.|;|$)',
        text, re.IGNORECASE,
    )
    for dec in decision_patterns:
        # Try to extract rationale from "because" / "since" clauses
        rationale = ""
        rat_match = re.search(r'\b(?:because|since|due to|so that)\s+(.+)', dec, re.IGNORECASE)
        if rat_match:
            rationale = rat_match.group(1).strip()
            title_part = dec[:dec.lower().find(rat_match.group(0).lower())].strip()
        else:
            title_part = dec.strip()
        decisions.append({
            "title": title_part[:60] if title_part else dec.strip()[:60],
            "rationale": rationale,
            "type": "decision",
        })

    # ── Question extraction ────────────────────────────────────────────

    for line in text.split('\n'):
        line = line.strip()
        if line.endswith('?') and len(line) > 10:
            questions.append({
                "question": line,
                "context": "",
                "type": "question",
            })

    # Also extract inline question patterns
    q_patterns = re.findall(
        r'(?:question about|wondering about|curious about|not sure (?:if|whether|how|why))\s+'
        r'(.{5,100}?)(?:\.|;|$)',
        text, re.IGNORECASE,
    )
    for q in q_patterns:
        q_text = q.strip()
        if not q_text.endswith('?'):
            q_text += '?'
        if not any(existing.get("question", "").lower() == q_text.lower() for existing in questions):
            questions.append({
                "question": q_text,
                "context": "",
                "type": "question",
            })

    # ── Connection detection ───────────────────────────────────────────

    conn_patterns = [
        r'(?:similar to|same as|connects to|related to|reminds me of)\s+["\']?(\w[\w\s]{2,30})',
        r'(\w[\w\s]{2,30})\s+(?:is like|is related to|is similar to)',
    ]
    for pattern in conn_patterns:
        matches = re.findall(pattern, text, re.IGNORECASE)
        for m in matches:
            connections.append({
                "from_title": "",  # needs resolution
                "to_title": m.strip(),
                "type": "relates_to",
                "why": "detected in text",
            })

    # ── Bridge opportunity detection ───────────────────────────────────

    # 1. Explicit cross-domain patterns: "X is similar to Y", "X reminds me of Y",
    #    "like X but for Y"
    bridge_patterns = [
        # "X is similar to Y" / "X reminds me of Y"
        (r'(\w[\w\s]{2,30}?)\s+(?:is similar to|reminds me of|is like|is analogous to)\s+'
         r'(\w[\w\s]{2,30})'),
        # "like X but for Y"
        r'like\s+(\w[\w\s]{2,30}?)\s+but\s+for\s+(\w[\w\s]{2,30})',
    ]
    for pattern in bridge_patterns:
        matches = re.findall(pattern, text, re.IGNORECASE)
        for m in matches:
            a, b = m[0].strip(), m[1].strip()
            if a and b and a.lower() != b.lower():
                bridge_opportunities.append({
                    "concept_a": a,
                    "concept_b": b,
                    "potential_link": f"Cross-domain analogy detected in text",
                })

    # 2. Concepts in the text that match existing graph titles
    all_extracted_titles = [c["title"].lower() for c in concepts]
    text_lower = text.lower()
    matching_existing = []
    for et_lower, et_original in existing_lower.items():
        if et_lower in text_lower and len(et_lower) > 3:
            matching_existing.append(et_original)

    # Bridge: connect newly extracted concepts to matching existing titles
    if matching_existing and concepts:
        for existing_title in matching_existing[:5]:
            for concept in concepts[:5]:
                if concept["title"].lower() != existing_title.lower():
                    bridge_opportunities.append({
                        "concept_a": concept["title"],
                        "concept_b": existing_title,
                        "potential_link": (
                            f"New concept '{concept['title']}' co-occurs with "
                            f"existing node '{existing_title}' in the same text"
                        ),
                    })

    # 3. Cross-paragraph concept bridging: concepts appearing in different paragraphs
    paragraphs = [p.strip() for p in text.split('\n\n') if p.strip()]
    if len(paragraphs) >= 2:
        para_concepts: list[set[str]] = []
        for para in paragraphs:
            para_lower = para.lower()
            found = set()
            for c in concepts:
                if c["title"].lower() in para_lower:
                    found.add(c["title"])
            para_concepts.append(found)

        # Find concepts that appear in different paragraphs (cross-topic bridging)
        for i in range(len(para_concepts)):
            for j in range(i + 1, len(para_concepts)):
                shared = para_concepts[i] & para_concepts[j]
                only_i = para_concepts[i] - shared
                only_j = para_concepts[j] - shared
                for ci in list(only_i)[:2]:
                    for cj in list(only_j)[:2]:
                        bridge_opportunities.append({
                            "concept_a": ci,
                            "concept_b": cj,
                            "potential_link": (
                                "Concepts appear in different sections of the same text, "
                                "suggesting a cross-domain connection"
                            ),
                        })

    return {
        "concepts": concepts[:10],
        "decisions": decisions[:5],
        "questions": questions[:5],
        "connections": connections[:5],
        "bridge_opportunities": bridge_opportunities[:10],
    }

def extract(
    text: str,
    existing_titles: list[str],
    config: Config,
    ledger: BudgetLedger,
) -> dict:
    """Extract knowledge — LLM if available, keyword fallback otherwise."""
    result = llm_extract(text, existing_titles, config, ledger)
    if result is not None:
        return result
    return keyword_extract(text, existing_titles=existing_titles)

def build_nx(vault: Vault) -> nx.DiGraph:
    """Build a NetworkX directed graph from all vault nodes."""
    G = nx.DiGraph()

    for slug, node in vault.topics.items():
        G.add_node(slug, kind="topic", title=node.title,
                   weight=node.weight, domains=node.domains)

    for slug, node in vault.skills.items():
        G.add_node(slug, kind="skill", title=node.title,
                   level=node.level, domains=node.domains)

    for slug in list(vault.topics) + list(vault.skills):
        for edge in vault.edges_from(slug):
            if edge.target in vault.topics or edge.target in vault.skills:
                G.add_edge(slug, edge.target, weight=edge.weight, reason=edge.reason)

    return G

def weighted_bfs(vault: Vault, start: str, max_hops: int = 2,
                 min_weight: float = 0.1) -> list[TraversalResult]:
    """BFS with cumulative weight decay (product of edge weights along path)."""
    if start not in vault.topics and start not in vault.skills:
        return []

    visited = {start}
    result = [TraversalResult(start, 0, None, 1.0, 1.0)]
    frontier = [(start, 0, 1.0)]

    while frontier:
        current, depth, cum = frontier.pop(0)
        if depth >= max_hops:
            continue

        node = vault.get(current)
        if node is None:
            continue

        edges = sorted(node.connects_to, key=lambda e: e.weight, reverse=True)
        for edge in edges:
            if edge.target in visited:
                continue
            if vault.get(edge.target) is None:
                continue

            new_cum = cum * edge.weight
            if new_cum < min_weight:
                continue

            visited.add(edge.target)
            result.append(TraversalResult(
                edge.target, depth + 1, edge.reason, edge.weight, new_cum))
            frontier.append((edge.target, depth + 1, new_cum))

    return result

def text_search(vault: Vault, query: str, top_k: int = 10) -> list[tuple[str, float]]:
    """Simple keyword search across titles, bodies, tags, and domains.

    Returns (slug, score) sorted by score descending. No LLM needed.
    """
    query_terms = query.lower().split()
    scores: dict[str, float] = {}

    for slug in vault.all_slugs():
        node = vault.get(slug)
        if node is None:
            continue

        score = 0.0
        title = (node.title or "").lower()
        body = (node.body or "").lower()
        domains = " ".join(getattr(node, "domains", [])).lower()
        tags = " ".join(getattr(node, "tags", [])).lower()
        slug_text = slug.replace("-", " ").lower()

        for term in query_terms:
            if term in slug_text:
                score += 3.0  # slug match is strong signal
            if term in title:
                score += 2.0
            if term in domains or term in tags:
                score += 1.5
            if term in body:
                score += 0.5
                # Bonus for frequency
                score += min(body.count(term) * 0.1, 1.0)

        if score > 0:
            # Boost by node weight
            node_weight = getattr(node, "weight", 0.5) or 0.5
            scores[slug] = score * (0.5 + 0.5 * node_weight)

    ranked = sorted(scores.items(), key=lambda x: x[1], reverse=True)
    return ranked[:top_k]

def ppr(vault: Vault, start: str, top_k: int = 10,
        alpha: float = 0.85) -> list[tuple[str, float]]:
    """Personalized PageRank seeded from a node."""
    G = build_nx(vault)
    if start not in G:
        return []

    personalization = {n: 0.0 for n in G.nodes()}
    personalization[start] = 1.0
    scores = nx.pagerank(G, alpha=alpha, personalization=personalization, weight="weight")
    return sorted(scores.items(), key=lambda x: x[1], reverse=True)[:top_k]

def graph_stats(vault: Vault) -> GraphStats:
    G = build_nx(vault)
    if not G:
        return GraphStats()
    degrees = dict(G.degree())
    mx = max(degrees, key=degrees.get) if degrees else ""
    return GraphStats(
        node_count=G.number_of_nodes(),
        edge_count=G.number_of_edges(),
        density=nx.density(G),
        components=nx.number_weakly_connected_components(G),
        avg_degree=sum(degrees.values()) / len(degrees) if degrees else 0,
        max_degree_node=mx,
        max_degree=degrees.get(mx, 0),
    )

def centrality(vault: Vault, method: str = "betweenness") -> list[tuple[str, float]]:
    G = build_nx(vault)
    if not G:
        return []
    fn = {
        "betweenness": lambda: nx.betweenness_centrality(G, weight="weight"),
        "degree": lambda: nx.degree_centrality(G),
        "closeness": lambda: nx.closeness_centrality(G),
    }
    scores = fn.get(method, fn["betweenness"])()
    return sorted(scores.items(), key=lambda x: x[1], reverse=True)

def communities(vault: Vault) -> list[set[str]]:
    G = build_nx(vault)
    if not G:
        return []
    U = G.to_undirected()
    return list(nx.community.greedy_modularity_communities(U, weight="weight"))

def build_nx_from_store(store) -> nx.DiGraph:
    """Build a NetworkX directed graph from the Store."""
    G = nx.DiGraph()

    for node in store.all_nodes(limit=10000):
        G.add_node(node["id"], title=node["title"], type=node["type"],
                   weight=node.get("weight", 0.5),
                   domains=node.get("domains", []))

    for nid in list(G.nodes()):
        for edge in store.edges_from(nid):
            if edge["to_id"] in G:
                G.add_edge(nid, edge["to_id"],
                           weight=edge["weight"],
                           type=edge["type"],
                           provenance=edge.get("provenance", ""))

    return G

def store_stats(store) -> dict:
    """Compute graph statistics from Store."""
    G = build_nx_from_store(store)
    if not G:
        return {"nodes": 0, "edges": 0, "density": 0, "components": 0,
                "avg_degree": 0, "max_degree_node": "", "max_degree": 0}

    degrees = dict(G.degree())
    mx = max(degrees, key=degrees.get) if degrees else ""
    return {
        "nodes": G.number_of_nodes(),
        "edges": G.number_of_edges(),
        "density": round(nx.density(G), 4),
        "components": nx.number_weakly_connected_components(G),
        "avg_degree": round(sum(degrees.values()) / len(degrees), 2) if degrees else 0,
        "max_degree_node": mx,
        "max_degree": degrees.get(mx, 0),
    }

def suggest_cross_component_links(
    store,
    max_suggestions: int = 10,
) -> list[dict]:
    """Find candidate links between disconnected graph components.

    For each pair of components, picks the highest-weight node from each
    and uses FTS title/domain overlap to find plausible connections.
    Returns suggestions sorted by similarity score.
    """
    G = build_nx_from_store(store)
    if not G or G.number_of_nodes() < 2:
        return []

    components = list(nx.weakly_connected_components(G))
    if len(components) < 2:
        return []

    # Get representative nodes per component (top 3 by weight)
    comp_reps: list[list[dict]] = []
    for comp in components:
        if len(comp) < 1:
            continue
        members = []
        for nid in comp:
            data = G.nodes[nid]
            members.append({
                "id": nid,
                "title": data.get("title", ""),
                "type": data.get("type", "concept"),
                "weight": data.get("weight", 0),
                "domains": data.get("domains", ""),
            })
        members.sort(key=lambda m: m["weight"], reverse=True)
        comp_reps.append(members[:3])

    # Compare representatives across components using keyword overlap
    suggestions = []
    seen_pairs: set[tuple[str, str]] = set()

    for i, reps_a in enumerate(comp_reps):
        for j, reps_b in enumerate(comp_reps):
            if j <= i:
                continue
            for a in reps_a:
                for b in reps_b:
                    pair = tuple(sorted([a["id"], b["id"]]))
                    if pair in seen_pairs:
                        continue
                    seen_pairs.add(pair)

                    score = _title_similarity(a["title"], b["title"])

                    # Domain overlap bonus
                    domains_a = _parse_domains(a["domains"])
                    domains_b = _parse_domains(b["domains"])
                    if domains_a and domains_b:
                        overlap = domains_a & domains_b
                        if overlap:
                            score += 0.3 * len(overlap)

                    if score > 0.1:
                        suggestions.append({
                            "concept_a": a["title"],
                            "concept_b": b["title"],
                            "id_a": a["id"],
                            "id_b": b["id"],
                            "score": round(score, 3),
                            "reason": f"Cross-component link (similarity: {score:.2f})",
                        })

            if len(suggestions) >= max_suggestions * 3:
                break
        if len(suggestions) >= max_suggestions * 3:
            break

    suggestions.sort(key=lambda s: s["score"], reverse=True)
    return suggestions[:max_suggestions]

def _title_similarity(a: str, b: str) -> float:
    """Simple word-overlap similarity between two titles."""
    if not a or not b:
        return 0.0
    words_a = set(a.lower().split())
    words_b = set(b.lower().split())
    stop = {"the", "a", "an", "is", "in", "of", "to", "and", "for", "with", "on", "at", "by"}
    words_a -= stop
    words_b -= stop
    if not words_a or not words_b:
        return 0.0
    overlap = words_a & words_b
    if not overlap:
        return 0.0
    return len(overlap) / min(len(words_a), len(words_b))

def _parse_domains(domains) -> set[str]:
    """Parse domains from various formats (JSON string, list, etc.)."""
    if isinstance(domains, list):
        return {d.lower() for d in domains}
    if isinstance(domains, str) and domains:
        import json
        try:
            parsed = json.loads(domains)
            if isinstance(parsed, list):
                return {d.lower() for d in parsed}
        except (json.JSONDecodeError, TypeError):
            return {d.strip().lower() for d in domains.split(",") if d.strip()}
    return set()

def _project_slug(project_root: Path) -> str:
    """Generate a stable slug from a project path."""
    # Use last two path components for uniqueness
    parts = project_root.parts
    if len(parts) >= 2:
        return f"proj-{parts[-2]}-{parts[-1]}".lower().replace(" ", "-")
    return f"proj-{parts[-1]}".lower().replace(" ", "-")

def _infer_title(project_root: Path, claude_md: Path) -> str:
    """Infer project title from CLAUDE.md or directory name."""
    try:
        text = claude_md.read_text(errors="replace")[:2000]
        # Look for a markdown heading
        for line in text.split("\n"):
            line = line.strip()
            if line.startswith("# ") and len(line) > 3:
                return line[2:].strip()
    except OSError:
        pass
    return project_root.name.replace("-", " ").replace("_", " ").title()

def _extract_project_context(claude_md: Path) -> str:
    """Extract the key content from a CLAUDE.md file."""
    try:
        text = claude_md.read_text(errors="replace")
        # Limit to reasonable size but keep the important stuff
        if len(text) > 4000:
            text = text[:4000] + "\n...(truncated)"
        return text.strip()
    except OSError:
        return ""

def _infer_domains(project_root: Path) -> list[str]:
    """Infer domains from project structure."""
    domains = []
    indicators = {
        "pyproject.toml": "python",
        "package.json": "javascript",
        "Cargo.toml": "rust",
        "go.mod": "go",
        "pom.xml": "java",
        "Gemfile": "ruby",
    }
    for filename, domain in indicators.items():
        if (project_root / filename).exists():
            domains.append(domain)

    # Check parent dir for broader domain hints
    parent_name = project_root.parent.name.lower()
    domain_map = {
        "code": "engineering",
        "personal": "personal",
        "research": "research",
        "work": "work",
    }
    if parent_name in domain_map:
        domains.append(domain_map[parent_name])

    return domains

def _extract_session_text(jsonl_path: Path, max_chars: int = 8000) -> str:
    """Extract human-readable text from a Claude Code JSONL session file."""
    texts = []
    total_len = 0

    try:
        with open(jsonl_path, "r", errors="replace") as f:
            for line in f:
                if total_len >= max_chars:
                    break
                try:
                    entry = json.loads(line)
                except (json.JSONDecodeError, ValueError):
                    continue

                # Extract text from assistant messages
                role = entry.get("role", "")
                if role != "assistant":
                    continue

                content = entry.get("content", "")
                if isinstance(content, str):
                    texts.append(content[:1000])
                    total_len += len(content[:1000])
                elif isinstance(content, list):
                    for block in content:
                        if isinstance(block, dict) and block.get("type") == "text":
                            text = block.get("text", "")[:1000]
                            texts.append(text)
                            total_len += len(text)
    except OSError:
        return ""

    return "\n".join(texts)

def scan_kin_files(config: Config, store: Store, verbose: bool = False) -> int:
    """Scan project directories for .kin files (per-repo metadata).

    A .kin file in a repo root provides Kindex-specific metadata:
      audience: team
      domains: [engineering, python]
      connects_to: [other-project-slug]
      description: What this project is about.

    Returns count of updated nodes.
    """
    import yaml

    count = 0
    for project_dir in config.resolved_project_dirs:
        if not project_dir.exists():
            continue

        for conv_file in sorted(project_dir.rglob(".kin")):
            project_root = conv_file.parent
            slug = _project_slug(project_root)

            try:
                data = yaml.safe_load(conv_file.read_text()) or {}
            except Exception:
                continue

            existing = store.get_node(slug)
            if existing:
                # Update from .conv metadata
                updates = {}
                if "audience" in data:
                    updates["audience"] = data["audience"]
                if "domains" in data:
                    updates["domains"] = data["domains"]
                if "description" in data:
                    updates["content"] = data["description"]
                if updates:
                    store.update_node(slug, **updates)
                    count += 1
                    if verbose:
                        print(f"  Updated from .kin: {slug}")

                # Handle connects_to
                for target in data.get("connects_to", []):
                    target_node = store.get_node(target) or store.get_node_by_title(target)
                    if target_node:
                        store.add_edge(slug, target_node["id"],
                                       edge_type="relates_to",
                                       weight=0.6,
                                       provenance=".kin file")
            else:
                # Create from .conv if CLAUDE.md scan missed it
                title = data.get("title", project_root.name.replace("-", " ").title())
                audience = data.get("audience", _infer_audience(project_root))
                store.add_node(
                    node_id=slug,
                    title=title,
                    content=data.get("description", ""),
                    node_type="project",
                    domains=data.get("domains", _infer_domains(project_root)),
                    audience=audience,
                    prov_source=str(conv_file),
                    prov_activity="kin-file-scan",
                    extra={"path": str(project_root)},
                )
                count += 1
                if verbose:
                    print(f"  Created from .kin: {slug}")

    return count

def _resolve_kin_recursive(
    kin_path: Path,
    chain: list[dict],
    visited: set,
    remaining: int,
) -> None:
    """Recursively resolve .kin inheritance chain."""
    import yaml

    resolved = kin_path.expanduser().resolve()
    if str(resolved) in visited or remaining <= 0:
        return
    visited.add(str(resolved))

    if not resolved.exists():
        return

    try:
        data = yaml.safe_load(resolved.read_text()) or {}
    except Exception:
        return

    data["_source"] = str(resolved)
    chain.append(data)

    # Resolve inherited .kin files
    for parent_ref in data.get("inherits", []):
        parent_path = (resolved.parent / parent_ref).resolve()
        _resolve_kin_recursive(parent_path, chain, visited, remaining - 1)

def merge_kin_chain(chain: list[dict]) -> dict:
    """Merge an inheritance chain into a single resolved config.

    Later entries (ancestors) provide defaults; earlier entries (local) override.
    Lists are concatenated. Dicts are merged (local wins). Scalars are overridden.
    """
    if not chain:
        return {}

    result: dict = {}

    # Process from ancestor (end) to local (start) — local overrides
    for layer in reversed(chain):
        for key, value in layer.items():
            if key.startswith("_"):
                continue
            if key == "inherits":
                continue
            if key in result:
                existing = result[key]
                if isinstance(existing, list) and isinstance(value, list):
                    # Concatenate lists, dedup
                    seen = set()
                    merged = []
                    for item in value + existing:
                        s = str(item)
                        if s not in seen:
                            seen.add(s)
                            merged.append(item)
                    result[key] = merged
                elif isinstance(existing, dict) and isinstance(value, dict):
                    existing.update(value)
                else:
                    result[key] = value
            else:
                result[key] = value

    result["_chain"] = [d.get("_source", "?") for d in chain]
    return result

def _infer_audience(project_root: Path) -> str:
    """Infer audience from directory heuristic."""
    path_str = str(project_root).lower()
    if "/personal/" in path_str or "/gemweaver/" in path_str:
        return "private"
    if "/work/" in path_str:
        return "team"
    if "/code/" in path_str:
        return "team"  # code repos default to team-visible
    return "private"

def load_synonym_rings(config: "Config", store: "Store", verbose: bool = False) -> int:
    """Load synonym ring files from the data directory.

    Synonym ring format (.syn files in data_dir/synonyms/):
        ring: database-terms
        synonyms:
          - database
          - db
          - datastore
          - data store
          - persistence layer

    Applies synonyms as AKA entries on matching nodes.
    Returns count of nodes updated.
    """
    import yaml

    syn_dir = config.data_path / "synonyms"
    if not syn_dir.exists():
        return 0

    count = 0
    for syn_file in sorted(syn_dir.glob("*.syn")):
        try:
            data = yaml.safe_load(syn_file.read_text()) or {}
        except Exception:
            if verbose:
                print(f"  Warning: could not parse {syn_file.name}")
            continue

        ring_name = data.get("ring", syn_file.stem)
        synonyms = data.get("synonyms", [])
        if not synonyms or not isinstance(synonyms, list):
            continue

        # For each synonym, find nodes whose title matches and add
        # all other synonyms as AKA entries
        for synonym in synonyms:
            node = store.get_node_by_title(synonym)
            if not node:
                continue

            existing_aka = list(node.get("aka") or [])
            new_aka = list(existing_aka)
            added = False

            for other in synonyms:
                if other == synonym:
                    continue
                if other.lower() == node.get("title", "").lower():
                    continue
                if other not in new_aka:
                    new_aka.append(other)
                    added = True

            if added:
                store.update_node(node["id"], aka=new_aka)
                count += 1
                if verbose:
                    added_count = len(new_aka) - len(existing_aka)
                    print(f"  {node['title']}: +{added_count} synonyms from ring '{ring_name}'")

    return count

def _now_iso() -> str:
    """Return current timestamp in ISO format."""
    from datetime import datetime
    return datetime.now(tz=None).isoformat(timespec="seconds")

def get_client(config: Config):
    """Get anthropic client, or None if not available."""
    if not config.llm.enabled:
        return None
    try:
        import os
        import anthropic
        api_key = os.environ.get(config.llm.api_key_env)
        if not api_key:
            import sys
            print(f"Warning: LLM enabled but {config.llm.api_key_env} not set. "
                  f"Falling back to keyword matching.", file=sys.stderr)
            return None
        return anthropic.Anthropic(api_key=api_key)
    except ImportError:
        import sys
        print("Warning: LLM enabled but 'anthropic' package not installed. "
              "Install with: pip install kindex[llm]", file=sys.stderr)
        return None

def _json(obj: Any, **kw) -> str:
    """JSON serialize with date/path handling."""
    import datetime
    from pathlib import Path

    def default(o):
        if isinstance(o, (datetime.date, datetime.datetime)):
            return o.isoformat()
        if isinstance(o, Path):
            return str(o)
        if isinstance(o, set):
            return sorted(o)
        raise TypeError(f"Not JSON serializable: {type(o)}")

    return json.dumps(obj, default=default, **kw)

def _node_detail(store, node: dict) -> str:
    """Multi-line detail view of a node with edges."""
    lines = [
        f"# {node.get('title', node['id'])}",
        f"Type: {node.get('type', 'concept')}  |  Weight: {node.get('weight', 0):.2f}  |  "
        f"Audience: {node.get('audience', 'private')}",
        f"ID: {node['id']}",
    ]
    if node.get("domains"):
        lines.append(f"Tags: {', '.join(node.get('tags') or node.get('domains') or [])}")
    if node.get("aka"):
        lines.append(f"AKA: {', '.join(node['aka'])}")
    if node.get("content"):
        lines.append(f"\n{node['content']}")

    edges = store.edges_from(node["id"])
    if edges:
        lines.append(f"\n## Connections ({len(edges)})")
        for e in edges[:20]:
            lines.append(f"  -> {e.get('to_title', e['to_id'])} ({e['type']}, w={e['weight']:.2f})")

    prov_parts = []
    if node.get("prov_who"):
        prov_parts.append(f"who={node['prov_who']}")
    if node.get("prov_activity"):
        prov_parts.append(f"activity={node['prov_activity']}")
    if node.get("prov_source"):
        prov_parts.append(f"source={node['prov_source']}")
    if prov_parts:
        lines.append(f"\nProvenance: {', '.join(prov_parts)}")

    extra = node.get("extra")
    if extra and isinstance(extra, dict):
        state = extra.get("current_state")
        if state:
            lines.append(f"\nState: {_json(state)}")

    return "\n".join(lines)

def context(
    topic: str = "",
    level: str = "abridged",
    max_tokens: int = 0,
) -> str:
    """Get a formatted context block for injection into conversation.

    Args:
        topic: Topic to search for (auto-detects from cwd if empty).
        level: Context tier (full, abridged, summarized, executive, index).
        max_tokens: Token budget (overrides level with auto-selection if set).
    """
    store, _ = _get_store()
    from .retrieve import format_context_block, hybrid_search

    if topic:
        results = hybrid_search(store, topic, top_k=15)
    else:
        # Fall back to recent high-weight nodes
        results = store.recent_nodes(n=15)

    if not results:
        return "No relevant knowledge found."

    kwargs = {"level": level}
    if max_tokens > 0:
        kwargs = {"max_tokens_approx": max_tokens}

    return format_context_block(store, results, query=topic, **kwargs)

def show(node_id: str) -> str:
    """Show full details of a node including edges and provenance.

    Args:
        node_id: Node ID or title to look up.
    """
    store, _ = _get_store()
    node = store.get_node(node_id) or store.get_node_by_title(node_id)
    if not node:
        return f"Node not found: {node_id}"
    return _node_detail(store, node)

def status() -> str:
    """Get knowledge graph health and statistics.

    Returns node/edge counts, type distribution, orphan count,
    and active operational nodes (constraints, watches, directives).
    """
    store, _ = _get_store()
    stats = store.stats()
    op = store.operational_summary()

    lines = [
        "# Kindex Status\n",
        f"Nodes: {stats.get('node_count', 0)}",
        f"Edges: {stats.get('edge_count', 0)}",
        f"Orphans: {stats.get('orphan_count', 0)}",
    ]

    type_counts = stats.get("type_counts", {})
    if type_counts:
        lines.append("\n## Node Types")
        for t, c in sorted(type_counts.items(), key=lambda x: -x[1]):
            lines.append(f"  {t}: {c}")

    constraints = op.get("constraints", [])
    if constraints:
        lines.append(f"\n## Active Constraints ({len(constraints)})")
        for c in constraints[:10]:
            lines.append(f"  - {c.get('title', c['id'])}")

    watches = op.get("watches", [])
    if watches:
        lines.append(f"\n## Active Watches ({len(watches)})")
        for w in watches[:10]:
            lines.append(f"  - {w.get('title', w['id'])}")

    return "\n".join(lines)

def resource_status() -> str:
    """Current knowledge graph statistics."""
    store, _ = _get_store()
    stats = store.stats()
    return _json(stats, indent=2)

def resource_node(node_id: str) -> str:
    """Full details of a specific knowledge node."""
    store, _ = _get_store()
    node = store.get_node(node_id) or store.get_node_by_title(node_id)
    if not node:
        return f"Node not found: {node_id}"
    return _node_detail(store, node)

def resource_orphans() -> str:
    """Nodes with no connections (candidates for linking or removal)."""
    store, _ = _get_store()
    orphans = store.orphans()
    if not orphans:
        return "No orphan nodes."
    lines = [_node_summary(n) for n in orphans]
    return f"{len(orphans)} orphan(s):\n" + "\n".join(lines)

def orient() -> str:
    """Quick orientation: graph stats, recent activity, and key nodes."""
    store, _ = _get_store()
    from .graph import store_stats

    stats = store_stats(store)
    recent = store.recent_nodes(n=10)
    op = store.operational_summary()

    lines = [
        "# Kindex Orientation\n",
        f"Graph: {stats.get('nodes', 0)} nodes, {stats.get('edges', 0)} edges, "
        f"{stats.get('components', 0)} component(s)\n",
    ]

    if recent:
        lines.append("## Recently Active")
        for n in recent[:10]:
            lines.append(f"  - {_node_summary(n)}")

    constraints = op.get("constraints", [])
    if constraints:
        lines.append(f"\n## Active Constraints ({len(constraints)})")
        for c in constraints[:5]:
            lines.append(f"  - {c.get('title', c['id'])}")

    watches = op.get("watches", [])
    if watches:
        lines.append(f"\n## Active Watches ({len(watches)})")
        for w in watches[:5]:
            lines.append(f"  - {w.get('title', w['id'])}")

    return "\n".join(lines)

def tag_resume(name: str = "", tokens: int = 1500) -> str:
    """Resume a session tag — get full context for continuing work.

    Args:
        name: Tag name to resume (shows active/paused tags if empty).
        tokens: Token budget for context block.
    """
    store, _ = _get_store()
    from .sessions import format_resume_context, list_tags

    if not name:
        tags = list_tags(store, status="active", limit=5)
        tags += list_tags(store, status="paused", limit=5)
        if not tags:
            return "No active or paused session tags."
        lines = ["Available session tags:\n"]
        for t in tags:
            extra = t.get("extra") or {}
            lines.append(f"  [{extra.get('session_status', '?')}] "
                         f"{extra.get('tag', t['title'])}: "
                         f"{extra.get('current_focus', '')[:60]}")
        return "\n".join(lines)

    return format_resume_context(store, name, max_tokens=tokens)

def watch_list(status: str = "active") -> str:
    """List watch nodes.

    Args:
        status: Filter by status: active (default), archived, all.
    """
    store, _ = _get_store()
    if status == "all":
        watches = store.all_nodes(node_type="watch", limit=50)
    elif status == "archived":
        watches = store.all_nodes(node_type="watch", status="archived", limit=50)
    else:
        watches = store.active_watches()

    if not watches:
        return "No watches found."

    lines = [f"Watches ({len(watches)}):"]
    for w in watches:
        extra = w.get("extra") or {}
        parts = [f"- {w['title']} (id={w['id']})"]
        if extra.get("owner"):
            parts.append(f"@{extra['owner']}")
        if extra.get("expires"):
            parts.append(f"expires {extra['expires']}")
        lines.append(" ".join(parts))
    return "\n".join(lines)

def remind_check() -> str:
    """Check for due reminders and fire notifications.

    Runs the reminder check cycle: finds due reminders, sends notifications,
    handles auto-snooze for stale fired reminders.
    """
    store, config = _get_store()
    from .reminders import auto_snooze_stale, check_and_fire
    fired = check_and_fire(store, config)
    snoozed = auto_snooze_stale(store, config)
    if not fired and snoozed == 0:
        return "No due reminders."
    parts = []
    if fired:
        parts.append(f"{len(fired)} reminder(s) fired")
        for r in fired:
            parts.append(f"  - {r['title']} [{r.get('priority', 'normal')}]")
    if snoozed:
        parts.append(f"{snoozed} auto-snoozed")
    return "\n".join(parts)

