def _parse_time_of_day(text: str) -> tuple[int, int]:
    """Parse time-of-day strings like '9am', '3:30pm', '14:00' into (hour, minute)."""
    text = text.strip().lower()

    # 24-hour: "14:00", "9:30"
    m = re.match(r"^(\d{1,2}):(\d{2})$", text)
    if m:
        return int(m.group(1)), int(m.group(2))

    # 12-hour with minutes: "3:30pm", "11:45am"
    m = re.match(r"^(\d{1,2}):(\d{2})\s*(am|pm)$", text)
    if m:
        h, mi, ampm = int(m.group(1)), int(m.group(2)), m.group(3)
        if ampm == "pm" and h != 12:
            h += 12
        elif ampm == "am" and h == 12:
            h = 0
        return h, mi

    # 12-hour without minutes: "9am", "3pm", "12pm"
    m = re.match(r"^(\d{1,2})\s*(am|pm)$", text)
    if m:
        h, ampm = int(m.group(1)), m.group(2)
        if ampm == "pm" and h != 12:
            h += 12
        elif ampm == "am" and h == 12:
            h = 0
        return h, 0

    # Bare number: treat as hour in 24-hour time
    m = re.match(r"^(\d{1,2})$", text)
    if m:
        return int(m.group(1)), 0

    raise ValueError(f"Cannot parse time: {text!r}")

def _compute_next_due(rrule_str: str, after: datetime.datetime | None = None) -> str:
    """Use dateutil.rrule to compute the next occurrence after a given datetime."""
    from dateutil.rrule import rrulestr

    after = after or _now_dt()
    # rrulestr needs a DTSTART for context
    rule = rrulestr(rrule_str, dtstart=after)
    nxt = rule.after(after)
    if nxt is None:
        raise ValueError(f"No future occurrence for rule: {rrule_str}")
    return nxt.isoformat(timespec="seconds")

def _parse_recurring(text: str) -> tuple[str, str]:
    """Parse recurring natural language into (rrule_string, next_due_iso).

    Handles patterns like:
    - "every 30 minutes", "every 2 hours", "every 3 days"
    - "every day at 9am", "every weekday at 9am"
    - "every monday", "every friday at 5pm"
    - "every monday and wednesday at 3pm"
    - "every month on day 15"
    - "daily", "weekly", "hourly", "monthly"
    """
    t = text.strip().lower()

    # Shorthands: "daily", "weekly", "hourly", "monthly"
    if t in ("daily", "weekly", "hourly", "monthly"):
        freq = {"daily": "DAILY", "weekly": "WEEKLY",
                "hourly": "HOURLY", "monthly": "MONTHLY"}[t]
        rrule = f"FREQ={freq}"
        return rrule, _compute_next_due(rrule)

    # "daily at <time>"
    m = re.match(r"(?:every\s+day|daily)\s+at\s+(.+)", t)
    if m:
        h, mi = _parse_time_of_day(m.group(1))
        rrule = f"FREQ=DAILY;BYHOUR={h};BYMINUTE={mi};BYSECOND=0"
        return rrule, _compute_next_due(rrule)

    # "every weekday at <time>"
    m = re.match(r"every\s+weekday\s+at\s+(.+)", t)
    if m:
        h, mi = _parse_time_of_day(m.group(1))
        rrule = f"FREQ=WEEKLY;BYDAY=MO,TU,WE,TH,FR;BYHOUR={h};BYMINUTE={mi};BYSECOND=0"
        return rrule, _compute_next_due(rrule)

    # "every weekday" (no time)
    m = re.match(r"every\s+weekday$", t)
    if m:
        rrule = "FREQ=WEEKLY;BYDAY=MO,TU,WE,TH,FR"
        return rrule, _compute_next_due(rrule)

    # "every <day(s)> at <time>" — e.g. "every monday and wednesday at 3pm"
    m = re.match(r"every\s+((?:(?:mon|tue|wed|thu|fri|sat|sun)\w*(?:\s+and\s+|\s*,\s*)?)+)\s+at\s+(.+)", t)
    if m:
        days_str, time_str = m.group(1), m.group(2)
        day_names = re.findall(r"(mon|tue|wed|thu|fri|sat|sun)\w*", days_str)
        byday = ",".join(_DOW_MAP[d] for d in day_names if d in _DOW_MAP)
        if byday:
            h, mi = _parse_time_of_day(time_str)
            rrule = f"FREQ=WEEKLY;BYDAY={byday};BYHOUR={h};BYMINUTE={mi};BYSECOND=0"
            return rrule, _compute_next_due(rrule)

    # "every <day>" — e.g. "every monday"
    m = re.match(r"every\s+(mon\w*|tue\w*|wed\w*|thu\w*|fri\w*|sat\w*|sun\w*)$", t)
    if m:
        day = re.match(r"(mon|tue|wed|thu|fri|sat|sun)", m.group(1))
        if day and day.group(1) in _DOW_MAP:
            byday = _DOW_MAP[day.group(1)]
            rrule = f"FREQ=WEEKLY;BYDAY={byday}"
            return rrule, _compute_next_due(rrule)

    # "every N <unit>" — e.g. "every 30 minutes", "every 2 hours"
    m = re.match(r"every\s+(\d+)\s+(minute|minutes|hour|hours|day|days|week|weeks|month|months)", t)
    if m:
        interval = int(m.group(1))
        freq = _FREQ_MAP.get(m.group(2))
        if freq:
            rrule = f"FREQ={freq};INTERVAL={interval}"
            return rrule, _compute_next_due(rrule)

    # "every N <unit> at <time>"
    m = re.match(r"every\s+(\d+)\s+(day|days|week|weeks)\s+at\s+(.+)", t)
    if m:
        interval = int(m.group(1))
        freq = _FREQ_MAP.get(m.group(2))
        if freq:
            h, mi = _parse_time_of_day(m.group(3))
            rrule = f"FREQ={freq};INTERVAL={interval};BYHOUR={h};BYMINUTE={mi};BYSECOND=0"
            return rrule, _compute_next_due(rrule)

    # "every month on day N"
    m = re.match(r"every\s+month\s+on\s+(?:day\s+)?(\d{1,2})", t)
    if m:
        day_num = int(m.group(1))
        rrule = f"FREQ=MONTHLY;BYMONTHDAY={day_num}"
        return rrule, _compute_next_due(rrule)

    raise ValueError(f"Cannot parse recurring schedule: {text!r}")

def parse_time_spec(text: str) -> tuple[str, str, str]:
    """Parse a time specification into (next_due_iso, schedule_str, reminder_type).

    Supports:
    - Raw rrule: "RRULE:FREQ=DAILY" or "FREQ=DAILY"
    - Cron: "0 9 * * 1-5" (if cronsim available)
    - Recurring NL: "every weekday at 9am", "daily", "every 2 hours"
    - One-shot NL: "in 30 minutes", "tomorrow at 3pm", "next friday"
    """
    text = text.strip()

    # 1. Raw rrule pass-through
    if text.upper().startswith("RRULE:"):
        rrule_str = text[6:]
        return _compute_next_due(rrule_str), rrule_str, "recurring"
    if text.upper().startswith("FREQ="):
        return _compute_next_due(text), text, "recurring"

    # 2. Cron expression (5 space-separated fields)
    if re.match(r"^[\d*,/-]+\s+[\d*,/-]+\s+[\d*,/-]+\s+[\d*,/-]+\s+[\d*,/-]+$", text):
        try:
            from cronsim import CronSim
            it = CronSim(text, _now_dt())
            next_due = next(it)
            return next_due.isoformat(timespec="seconds"), text, "recurring"
        except ImportError:
            raise ValueError(
                f"Cron expressions require the 'cronsim' package: pip install cronsim"
            )

    # 3. Recurring NL — starts with "every" or is a shorthand
    lower = text.lower().strip()
    if lower.startswith("every ") or lower in ("daily", "weekly", "hourly", "monthly"):
        rrule_str, next_due = _parse_recurring(text)
        return next_due, rrule_str, "recurring"

    # Also match "daily at <time>"
    if lower.startswith("daily "):
        rrule_str, next_due = _parse_recurring(text)
        return next_due, rrule_str, "recurring"

    # 4. One-shot via dateparser
    try:
        import dateparser
    except ImportError:
        raise ValueError(
            "Natural language time parsing requires 'dateparser': pip install dateparser"
        )

    parsed = dateparser.parse(text, settings={
        "PREFER_DATES_FROM": "future",
        "RETURN_AS_TIMEZONE_AWARE": False,
    })
    if parsed is None:
        raise ValueError(f"Cannot parse time specification: {text!r}")

    # Sanity: must be in the future
    if parsed <= _now_dt():
        # dateparser might return a past date for ambiguous input; nudge forward
        parsed += datetime.timedelta(days=1)

    return parsed.isoformat(timespec="seconds"), "", "once"

def complete_reminder(store: Store, reminder_id: str) -> None:
    """Mark a one-shot reminder as completed, or advance a recurring one."""
    r = store.get_reminder(reminder_id)
    if r is None:
        raise ValueError(f"Reminder not found: {reminder_id}")

    if r["reminder_type"] == "recurring":
        advance_recurring(store, reminder_id)
    else:
        store.complete_reminder(reminder_id)
    _try_repack(store)

def format_reminder(reminder: dict) -> str:
    """Format a single reminder for display."""
    lines = []
    status = reminder.get("status", "active")
    priority = reminder.get("priority", "normal")
    p_marker = f" [{priority}]" if priority != "normal" else ""
    lines.append(f"  {reminder['id']}: {reminder['title']}{p_marker} ({status})")
    lines.append(f"    Due: {reminder['next_due']}")
    if reminder.get("schedule"):
        lines.append(f"    Schedule: {reminder['schedule']}")
    if reminder.get("body"):
        lines.append(f"    {reminder['body']}")
    if status == "snoozed" and reminder.get("snooze_until"):
        lines.append(f"    Snoozed until: {reminder['snooze_until']}")
    if reminder.get("snooze_count", 0) > 0:
        lines.append(f"    Snoozed {reminder['snooze_count']} time(s)")

    # Action info
    extra = reminder.get("extra") or {}
    if extra.get("action_command") or extra.get("action_instructions"):
        a_status = extra.get("action_status", "pending")
        a_mode = extra.get("action_mode", "auto")
        lines.append(f"    Action [{a_mode}]: {a_status}")
        if extra.get("action_command"):
            lines.append(f"      Command: {extra['action_command']}")
        if extra.get("action_instructions"):
            lines.append(f"      Instructions: {extra['action_instructions'][:80]}")
        if extra.get("action_result") and a_status in ("completed", "failed"):
            lines.append(f"      Result: {extra['action_result'][:120]}")

    return "\n".join(lines)

def format_reminder_list(reminders: list[dict]) -> str:
    """Format a list of reminders for display."""
    if not reminders:
        return "No reminders."
    return "\n".join(format_reminder(r) for r in reminders)

def parse_duration(text: str) -> int:
    """Parse a duration string like '15m', '1h', '30s', '2h30m' into seconds."""
    total = 0
    for match in re.finditer(r"(\d+)\s*(h|m|s|hr|min|sec|hour|minute|second)", text.lower()):
        val = int(match.group(1))
        unit = match.group(2)[0]
        if unit == "h":
            total += val * 3600
        elif unit == "m":
            total += val * 60
        elif unit == "s":
            total += val
    if total:
        return total
    # Bare number: treat as seconds
    if text.strip().isdigit():
        return int(text.strip())
    return 900  # default 15 min

def _strip_frontmatter(text: str) -> str:
    """Remove YAML frontmatter (---...---) from content."""
    return _FRONTMATTER_RE.sub("", text).lstrip()

def _rrf_merge(*ranked_lists: list[tuple[str, float]], k: int = 60) -> list[tuple[str, float]]:
    """Reciprocal Rank Fusion across multiple ranked result lists.

    Each input is [(node_id, score), ...] in descending score order.
    Returns merged [(node_id, rrf_score)] sorted by rrf_score descending.
    """
    scores: dict[str, float] = defaultdict(float)

    for ranked in ranked_lists:
        for rank, (nid, _) in enumerate(ranked):
            scores[nid] += 1.0 / (k + rank + 1)

    return sorted(scores.items(), key=lambda x: x[1], reverse=True)

def auto_select_tier(available_tokens: int | None = None) -> str:
    """Select the best context tier for the given token budget.

    If available_tokens is None, defaults to 'abridged' (safe middle ground).
    """
    if available_tokens is None:
        return "abridged"
    for tier in TIER_ORDER:
        if TIER_BUDGETS[tier] <= available_tokens:
            return tier
    return "index"

def _gather_domains(results: list[dict]) -> set[str]:
    domains: set[str] = set()
    for r in results:
        for d in (r.get("domains") or []):
            domains.add(d)
    return domains

def _append_operational(store: Store, lines: list[str], verbose: bool = False) -> None:
    """Append active operational nodes (constraints, watches, etc.) to output."""
    ops = store.operational_summary()

    if ops["constraints"]:
        lines.append("\n### Active constraints")
        for c in ops["constraints"][:5 if verbose else 3]:
            extra = c.get("extra") or {}
            action = extra.get("action", "warn")
            lines.append(f"- [{action}] {c['title']}")
            if verbose and extra.get("trigger"):
                lines.append(f"  trigger: {extra['trigger']}")

    if ops["watches"]:
        lines.append("\n### Watches")
        for w in ops["watches"][:5 if verbose else 3]:
            extra = w.get("extra") or {}
            parts = [f"! {w['title']}"]
            if extra.get("owner"):
                parts.append(f"@{extra['owner']}")
            if extra.get("expires"):
                parts.append(f"(expires {extra['expires']})")
            lines.append(f"- {' '.join(parts)}")

    if verbose and ops["checkpoints"]:
        lines.append("\n### Checkpoints")
        for cp in ops["checkpoints"][:5]:
            trig = (cp.get("extra") or {}).get("trigger", "")
            lines.append(f"- [ ] {cp['title']}" + (f" (trigger: {trig})" if trig else ""))

    if verbose and ops["directives"]:
        lines.append("\n### Directives")
        for d in ops["directives"][:5]:
            scope = (d.get("extra") or {}).get("scope", "")
            lines.append(f"- {d['title']}" + (f" [scope: {scope}]" if scope else ""))

def _format_index(store: Store, results: list[dict], query: str) -> str:
    """Index — node titles and edge types only. Just the map."""
    titles = []
    for r in results:
        title = r.get("title", r["id"])
        node_type = r.get("type", "concept")
        edges = r.get("edges_out", [])
        if edges:
            edge_types = set(e["type"] for e in edges[:3])
            titles.append(f"{title}({node_type})→[{','.join(edge_types)}]")
        else:
            titles.append(f"{title}({node_type})")
    return f"Kindex index: {' | '.join(titles)}\n"

def build_codebook_index(codebook_text: str) -> dict[str, str]:
    """Parse codebook text into {truncated_id: entry_number} mapping."""
    index: dict[str, str] = {}
    for line in codebook_text.split("\n"):
        if not line.startswith("#"):
            continue
        parts = line.split()
        if len(parts) >= 2:
            entry_num = parts[0]  # e.g. "#042"
            for part in parts:
                if part.startswith("id:"):
                    index[part[3:]] = entry_num
                    break
    return index

def predict_tier2(
    store: Store,
    query: str,
    search_results: list[dict],
    top_k: int = 8,
) -> list[dict]:
    """Expand search results with graph-predicted neighbors.

    Uses 1-hop edges from top hits to predict related nodes the user
    might ask about next. Returns merged list sorted by node ID for
    deterministic prefix ordering.
    """
    hit_ids = {r["id"] for r in search_results}
    predicted: dict[str, dict] = {}

    for hit in search_results[:3]:
        for edge in store.edges_from(hit["id"])[:5]:
            tid = edge["to_id"]
            if tid not in hit_ids and tid not in predicted:
                node = store.get_node(tid)
                if node and node.get("type") != "session":
                    predicted[tid] = node

    merged = list(search_results[:top_k])
    for node in sorted(predicted.values(), key=lambda n: n["id"]):
        if len(merged) >= top_k:
            break
        merged.append(node)
    return merged

def detect_domain_from_path(store: Store, cwd: str) -> list[str]:
    """Given a working directory, find relevant domain nodes.

    Searches for nodes whose prov_source matches the path.
    """
    # Search for nodes referencing this path
    results = store.fts_search(cwd, limit=5)
    domains: set[str] = set()
    for r in results:
        for d in (r.get("domains") or []):
            domains.add(d)
    return sorted(domains)

def nearest_reminder_seconds(store: "Store") -> int | None:
    """Return seconds until the nearest pending reminder, or None if none exist."""
    nearest = store.nearest_pending_reminder()
    if nearest is None:
        return None
    try:
        nearest_dt = datetime.datetime.fromisoformat(nearest)
    except (ValueError, TypeError):
        return None
    delta = (nearest_dt - _now_dt()).total_seconds()
    return max(0, int(delta))

def compute_optimal_interval(store: "Store", config: "Config") -> int:
    """Compute the optimal cron check interval based on nearest pending reminder.

    Returns 0 if no reminders are pending (daemon should be disabled).
    """
    if not config.reminders.adaptive_scheduling:
        return config.reminders.check_interval

    secs = nearest_reminder_seconds(store)
    if secs is None:
        return 0  # no pending reminders — disable

    tiers = sorted(config.reminders.schedule_tiers, key=lambda t: t.threshold, reverse=True)
    for tier in tiers:
        if secs > tier.threshold:
            return max(tier.interval, config.reminders.min_interval)

    # Fell through all tiers — use min_interval
    return config.reminders.min_interval

def repack_schedule(store: "Store", config: "Config") -> dict:
    """Compute optimal interval and apply it if changed. Returns status dict."""
    if not config.reminders.enabled:
        return {"action": "skipped", "reason": "reminders disabled"}

    interval = compute_optimal_interval(store, config)

    # Check current interval from meta table
    current = store.get_meta("cron_interval")
    current_int = int(current) if current else None

    if current_int == interval:
        return {"action": "unchanged", "interval": interval}

    result = apply_schedule(interval, config)
    store.set_meta("cron_interval", str(interval))
    result["interval"] = interval
    result["previous"] = current_int
    return result

def apply_schedule(interval: int, config: "Config") -> dict:
    """Apply a new cron interval to the system scheduler (launchd or crontab)."""
    if platform.system() == "Darwin":
        return _apply_launchd(interval, config)
    return _apply_crontab(interval, config)

def _apply_launchd(interval: int, config: "Config") -> dict:
    """Update the launchd plist with a new interval."""
    plist_path = Path.home() / "Library" / "LaunchAgents" / "com.kindex.cron.plist"

    if not plist_path.exists():
        if interval == 0:
            return {"action": "already_disabled"}
        # No plist exists — can't apply. User needs to run setup-cron first.
        return {"action": "skipped", "reason": "no plist installed"}

    if interval == 0:
        # Disable: unload the plist
        subprocess.run(
            ["launchctl", "unload", str(plist_path)],
            capture_output=True, timeout=5,
        )
        return {"action": "disabled"}

    # Read current plist, update the interval
    content = plist_path.read_text()
    new_content = re.sub(
        r"(<key>StartInterval</key>\s*<integer>)\d+(</integer>)",
        rf"\g<1>{interval}\g<2>",
        content,
    )

    if new_content == content:
        # Pattern not found — malformed plist
        return {"action": "skipped", "reason": "plist format unrecognized"}

    plist_path.write_text(new_content)

    # Reload: unload + load
    subprocess.run(
        ["launchctl", "unload", str(plist_path)],
        capture_output=True, timeout=5,
    )
    subprocess.run(
        ["launchctl", "load", str(plist_path)],
        capture_output=True, timeout=5,
    )
    return {"action": "updated"}

def _apply_crontab(interval: int, config: "Config") -> dict:
    """Update the crontab entry with a new interval."""
    result = subprocess.run(["crontab", "-l"], capture_output=True, text=True)
    if result.returncode != 0:
        return {"action": "skipped", "reason": "no crontab"}

    lines = result.stdout.splitlines()
    new_lines = [l for l in lines if "kin cron" not in l and "kindex" not in l]

    if interval > 0:
        from .setup import _find_kin_path
        kin_path = _find_kin_path()
        log_dir = config.data_path / "logs"
        # Convert interval to cron minutes (minimum 1)
        minutes = max(1, interval // 60)
        new_lines.append(f"*/{minutes} * * * * {kin_path} cron >> {log_dir}/cron.log 2>&1")

    new_crontab = "\n".join(new_lines) + "\n"
    proc = subprocess.run(["crontab", "-"], input=new_crontab,
                          capture_output=True, text=True)
    if proc.returncode == 0:
        return {"action": "disabled" if interval == 0 else "updated"}
    return {"action": "failed", "error": proc.stderr}

def _normalize_tag(name: str) -> str:
    """Normalize a tag name: lowercase, hyphens for spaces, strip special chars."""
    name = name.strip().lower()
    name = re.sub(r"[^a-z0-9\s-]", "", name)
    name = re.sub(r"[\s_]+", "-", name)
    return name.strip("-")

def get_tag(store: Store, name: str) -> dict | None:
    """Look up a session tag by name. Returns the node dict or None."""
    tag = store.get_session_tag_by_name(_normalize_tag(name))
    if tag:
        return tag
    # Also try unnormalized (in case title was stored differently)
    return store.get_session_tag_by_name(name)

def list_tags(
    store: Store,
    status: str | None = None,
    project_path: str | None = None,
    limit: int = 20,
) -> list[dict]:
    """List session tags with optional filters."""
