        status=status, project_path=project_path, limit=limit
    )

def update_tag(
    store: Store,
    name: str,
    *,
    description: str | None = None,
    focus: str | None = None,
    remaining: list[str] | None = None,
    append_remaining: list[str] | None = None,
    remove_remaining: list[str] | None = None,
) -> None:
    """Update the current state of a session tag."""
    tag = get_tag(store, name)
    if not tag:
        raise ValueError(f"Tag not found: {name}")

    extra = dict(tag.get("extra") or {})

    if focus is not None:
        extra["current_focus"] = focus
        # Also update the current open segment's focus
        segments = extra.get("segments", [])
        if segments:
            current = [s for s in segments if not s.get("ended_at")]
            if current:
                current[-1]["focus"] = focus

    if remaining is not None:
        extra["remaining"] = remaining

    if append_remaining:
        current_remaining = extra.get("remaining", [])
        extra["remaining"] = current_remaining + append_remaining

    if remove_remaining:
        current_remaining = extra.get("remaining", [])
        extra["remaining"] = [
            r for r in current_remaining if r not in remove_remaining
        ]

    updates: dict = {"extra": extra}
    if description is not None:
        updates["content"] = description

    store.update_node(tag["id"], **updates)

def link_node_to_tag(store: Store, tag_name: str, node_id: str) -> None:
    """Associate a knowledge node with a session tag."""
    tag = get_tag(store, tag_name)
    if not tag:
        return

    extra = dict(tag.get("extra") or {})
    linked = extra.get("linked_nodes", [])
    if node_id not in linked:
        linked.append(node_id)
        extra["linked_nodes"] = linked

        # Also update current segment's artifacts
        segments = extra.get("segments", [])
        for seg in segments:
            if not seg.get("ended_at"):
                artifacts = seg.get("artifacts", [])
                if node_id not in artifacts:
                    artifacts.append(node_id)
                    seg["artifacts"] = artifacts

        store.update_node(tag["id"], extra=extra)

    # Create a context_of edge from the node to the session tag
    try:
        store.add_edge(node_id, tag["id"], edge_type="context_of", provenance="session-tag")
    except Exception:
        pass  # Edge may already exist

def pause_tag(store: Store, name: str, *, summary: str = "") -> None:
    """Pause a session tag, marking it as suspended."""
    tag = get_tag(store, name)
    if not tag:
        raise ValueError(f"Tag not found: {name}")

    extra = dict(tag.get("extra") or {})
    extra["session_status"] = "paused"
    extra["paused_at"] = _now()

    if summary:
        # Update current segment summary
        for seg in extra.get("segments", []):
            if not seg.get("ended_at"):
                seg["summary"] = summary

    store.update_node(tag["id"], extra=extra)

def complete_tag(store: Store, name: str, *, summary: str = "") -> None:
    """Mark a session tag as completed."""
    tag = get_tag(store, name)
    if not tag:
        raise ValueError(f"Tag not found: {name}")

    extra = dict(tag.get("extra") or {})
    now = _now()
    extra["session_status"] = "completed"
    extra["completed_at"] = now

    # Close any open segments
    for seg in extra.get("segments", []):
        if not seg.get("ended_at"):
            seg["ended_at"] = now
            if summary:
                seg["summary"] = summary

    store.update_node(tag["id"], extra=extra)

def install_claude_hooks(config: "Config", dry_run: bool = False) -> list[str]:
    """Install Kindex hooks into Claude Code's settings.json.

    Adds:
    - SessionStart hook: kin prime --for hook
    - PreCompact hook: kin compact-hook --emit-context

    Preserves existing hooks. Returns list of actions taken.
    """
    settings_path = config.claude_path / "settings.json"
    actions = []

    # Read existing settings
    if settings_path.exists():
        data = json.loads(settings_path.read_text())
    else:
        data = {}

    hooks = data.setdefault("hooks", {})

    # Find kin binary path
    kin_path = _find_kin_path()

    # SessionStart hook
    session_start = hooks.setdefault("SessionStart", [])
    kindex_hook = {
        "matcher": "",
        "hooks": [{
            "type": "command",
            "command": f"{kin_path} prime --for hook",
            "timeout": 5000
        }]
    }
    # Check if already installed
    if not any("kin prime" in str(h) or "kindex" in str(h).lower() for h in session_start):
        session_start.append(kindex_hook)
        actions.append("Added SessionStart hook: kin prime --for hook")
    else:
        actions.append("SessionStart hook already installed")

    # PreCompact hook
    pre_compact = hooks.setdefault("PreCompact", [])
    compact_hook = {
        "matcher": "",
        "hooks": [{
            "type": "command",
            "command": f"{kin_path} compact-hook --emit-context",
            "timeout": 10000
        }]
    }
    if not any("compact-hook" in str(h) for h in pre_compact):
        pre_compact.append(compact_hook)
        actions.append("Added PreCompact hook: kin compact-hook --emit-context")
    else:
        actions.append("PreCompact hook already installed")

    # UserPromptSubmit hook — inject due reminders mid-session
    prompt_submit = hooks.setdefault("UserPromptSubmit", [])
    prompt_hook = {
        "matcher": "",
        "hooks": [{
            "type": "command",
            "command": f"{kin_path} prompt-check",
            "timeout": 2000
        }]
    }
    if not any("prompt-check" in str(h) for h in prompt_submit):
        prompt_submit.append(prompt_hook)
        actions.append("Added UserPromptSubmit hook: kin prompt-check")
    else:
        actions.append("UserPromptSubmit hook already installed")

    # Stop hook — guard for actionable reminders + session capture
    stop_hooks = hooks.setdefault("Stop", [])
    stop_guard_entry = {
        "matcher": "",
        "hooks": [
            {
                "type": "command",
                "command": f"{kin_path} stop-guard",
                "timeout": 5000,
            },
            {
                "type": "command",
                "command": f'{kin_path} compact-hook --text "Session ended"',
                "timeout": 5000,
            },
        ]
    }
    if not any("stop-guard" in str(h) for h in stop_hooks):
        # Replace existing Stop hooks with the combined guard + compact entry
        hooks["Stop"] = [stop_guard_entry]
        actions.append("Added Stop hook: kin stop-guard + compact-hook")
    else:
        actions.append("Stop hook already installed")

    if not dry_run:
        settings_path.parent.mkdir(parents=True, exist_ok=True)
        settings_path.write_text(json.dumps(data, indent=2) + "\n")
        actions.append(f"Wrote {settings_path}")

    return actions

def uninstall_launchd(dry_run: bool = False) -> list[str]:
    """Remove the launchd plist."""
    actions = []
    plist_path = Path.home() / "Library" / "LaunchAgents" / "com.kindex.cron.plist"

    if plist_path.exists():
        if not dry_run:
            subprocess.run(["launchctl", "unload", str(plist_path)],
                          capture_output=True, timeout=5)
            plist_path.unlink()
            actions.append("Unloaded and removed launchd plist")
        else:
            actions.append(f"Would remove: {plist_path}")
    else:
        actions.append("No launchd plist found")

    return actions

def _find_kin_path() -> str:
    """Find the kin executable path."""
    result = subprocess.run(["which", "kin"], capture_output=True, text=True, timeout=5)
    if result.returncode == 0 and result.stdout.strip():
        return result.stdout.strip()
    # Fallback to python -m
    import sys
    return f"{sys.executable} -m kindex.cli"

def _json_default(obj):
    if isinstance(obj, (_dt.date, _dt.datetime)):
        return obj.isoformat()
    if isinstance(obj, Path):
        return str(obj)
    raise TypeError(f"Not JSON serializable: {type(obj)}")

def _migrate_schema(self, current_version: int) -> None:
    """Apply incremental schema migrations. Uses self._conn directly
    to avoid triggering the conn property (which calls _init_schema)."""
    c = self._conn
    if current_version < 2:
        # v2: add audience column
        try:
            c.execute("ALTER TABLE nodes ADD COLUMN audience TEXT NOT NULL DEFAULT 'private'")
            c.execute("CREATE INDEX IF NOT EXISTS idx_nodes_audience ON nodes(audience)")
            c.commit()
        except Exception:
            pass  # column already exists

    if current_version < 3:
        # v3: add activity_log table
        try:
            c.executescript("""
                CREATE TABLE IF NOT EXISTS activity_log (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    timestamp TEXT NOT NULL DEFAULT (datetime('now')),
                    action TEXT NOT NULL,
                    target_id TEXT NOT NULL DEFAULT '',
                    target_title TEXT NOT NULL DEFAULT '',
                    actor TEXT NOT NULL DEFAULT '',
                    details TEXT NOT NULL DEFAULT ''
                );
                CREATE INDEX IF NOT EXISTS idx_activity_timestamp ON activity_log(timestamp);
                CREATE INDEX IF NOT EXISTS idx_activity_action ON activity_log(action);
            """)
            c.commit()
        except Exception:
            pass

    if current_version < 4:
        # v4: add suggestions table
        try:
            c.executescript("""
                CREATE TABLE IF NOT EXISTS suggestions (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    concept_a TEXT NOT NULL,
                    concept_b TEXT NOT NULL,
                    reason TEXT NOT NULL DEFAULT '',
                    source TEXT NOT NULL DEFAULT '',
                    status TEXT NOT NULL DEFAULT 'pending',
                    created_at TEXT NOT NULL DEFAULT (datetime('now'))
                );
                CREATE INDEX IF NOT EXISTS idx_suggestions_status ON suggestions(status);
            """)
            c.commit()
        except Exception:
            pass

    if current_version < 5:
        # v5: add reminders table
        try:
            c.executescript("""
                CREATE TABLE IF NOT EXISTS reminders (
                    id TEXT PRIMARY KEY,
                    title TEXT NOT NULL,
                    body TEXT DEFAULT '',
                    priority TEXT DEFAULT 'normal',
                    status TEXT DEFAULT 'active',
                    reminder_type TEXT DEFAULT 'once',
                    schedule TEXT DEFAULT '',
                    next_due TEXT NOT NULL,
                    last_fired TEXT,
                    snooze_until TEXT,
                    snooze_count INTEGER DEFAULT 0,
                    channels TEXT DEFAULT '[]',
                    related_node_id TEXT,
                    tags TEXT DEFAULT '',
                    extra TEXT DEFAULT '{}',
                    created_at TEXT DEFAULT (datetime('now')),
                    updated_at TEXT DEFAULT (datetime('now'))
                );
                CREATE INDEX IF NOT EXISTS idx_reminders_status ON reminders(status);
                CREATE INDEX IF NOT EXISTS idx_reminders_next_due ON reminders(next_due);
                CREATE INDEX IF NOT EXISTS idx_reminders_priority ON reminders(priority);
            """)
            c.commit()
        except Exception:
            pass

    if current_version < SCHEMA_VERSION:
        c.execute(
            "UPDATE meta SET value = ? WHERE key = 'schema_version'",
            (str(SCHEMA_VERSION),),
        )
        c.commit()

def close(self) -> None:
    if self._conn:
        self._conn.close()
        self._conn = None

def _log(self, action: str, target_id: str = "", target_title: str = "",
         actor: str = "", details: dict | None = None) -> None:
    """Record an action in the activity log."""
    try:
        self.conn.execute(
            """INSERT INTO activity_log (action, target_id, target_title, actor, details)
               VALUES (?, ?, ?, ?, ?)""",
            (action, target_id, target_title, actor,
             _jdumps(details or {})),
        )
        self.conn.commit()
    except Exception:
        pass  # don't let logging break operations

def recent_activity(self, limit: int = 50) -> list[dict]:
    """Get recent activity log entries."""
    try:
        rows = self.conn.execute(
            "SELECT * FROM activity_log ORDER BY timestamp DESC LIMIT ?",
            (limit,),
        ).fetchall()
        result = []
        for r in rows:
            d = dict(r)
            if isinstance(d.get("details"), str):
                try:
                    d["details"] = json.loads(d["details"])
                except (json.JSONDecodeError, TypeError):
                    pass
            result.append(d)
        return result
    except Exception:
        return []

def activity_since(self, since_iso: str, action: str | None = None) -> list[dict]:
    """Get activity log entries since a timestamp, optionally filtered by action type."""
