        if action:
            q += "AND action = ? "
            params.append(action)
        q += "ORDER BY timestamp DESC"
        rows = self.conn.execute(q, params).fetchall()
        result = []
        for r in rows:
            d = dict(r)
            if isinstance(d.get("details"), str):
