def update_reminder(self, reminder_id: str, **fields) -> None:
    """Update specific fields on a reminder."""
    allowed = {
        "title", "body", "priority", "status", "reminder_type",
        "schedule", "next_due", "last_fired", "snooze_until",
        "snooze_count", "channels", "related_node_id", "tags", "extra",
    }
    updates = []
    values = []
    for k, v in fields.items():
        if k not in allowed:
            continue
        if k in ("channels", "extra"):
            v = _jdumps(v)
        updates.append(f"{k} = ?")
        values.append(v)
    if not updates:
        return
    updates.append("updated_at = ?")
    values.append(_now())
    values.append(reminder_id)
    self.conn.execute(
        f"UPDATE reminders SET {', '.join(updates)} WHERE id = ?",
        values,
    )
    self.conn.commit()

def snooze_reminder(
    self, reminder_id: str, snooze_until: str, increment_count: bool = True,
) -> None:
    """Set a reminder to snoozed status."""
    fields: dict[str, Any] = {
        "status": "snoozed",
        "snooze_until": snooze_until,
    }
    if increment_count:
        r = self.get_reminder(reminder_id)
        if r:
            fields["snooze_count"] = r.get("snooze_count", 0) + 1
    self.update_reminder(reminder_id, **fields)
    self._log("snooze_reminder", reminder_id, "",
              details={"snooze_until": snooze_until})

def _reminder_to_dict(self, row: sqlite3.Row) -> dict:
    """Convert a reminder row to dict with JSON parsing."""
    d = dict(row)
    for key in ("channels", "extra"):
        if key in d and isinstance(d[key], str):
            try:
                d[key] = json.loads(d[key])
            except (json.JSONDecodeError, TypeError):
                pass
    return d

def stats(self) -> dict:
    node_count = self.conn.execute("SELECT COUNT(*) FROM nodes").fetchone()[0]
    edge_count = self.conn.execute("SELECT COUNT(*) FROM edges").fetchone()[0]
    orphan_count = len(self.orphans())
    type_counts = {}
    for row in self.conn.execute("SELECT type, COUNT(*) as c FROM nodes GROUP BY type"):
        type_counts[row["type"]] = row["c"]
    return {
        "nodes": node_count,
        "edges": edge_count,
        "orphans": orphan_count,
        "types": type_counts,
    }

def _row_to_dict(self, row: sqlite3.Row) -> dict:
    d = dict(row)
    for key in ("aka", "domains", "prov_who", "extra"):
        if key in d and isinstance(d[key], str):
            try:
                d[key] = json.loads(d[key])
            except (json.JSONDecodeError, TypeError):
                pass
    d["tags"] = d.get("domains") or []
    return d

def node_ids(self) -> list[str]:
    """All node IDs."""
    return [r[0] for r in self.conn.execute("SELECT id FROM nodes").fetchall()]

def _parse_priority(val: int | str) -> int:
    """Accept int 1-5 or label string, return int."""
    if isinstance(val, str):
        val = LABEL_TO_PRIORITY.get(val.lower(), 3)
    return max(1, min(5, int(val)))

def compute_task_weight(priority: int, due: str | None = None) -> float:
    """Compute node weight from priority and due-date urgency.

    Returns float in [0.01, 1.0]. Higher = more important.
    """
    base = PRIORITY_WEIGHTS.get(priority, 0.5)

    if due:
        try:
            due_dt = datetime.datetime.fromisoformat(due)
            hours_until = (due_dt - datetime.datetime.now()).total_seconds() / 3600
            if hours_until <= 0:
                base += 0.2  # overdue
            elif hours_until <= 24:
                base += 0.15  # due today
            elif hours_until <= 72:
                base += 0.05  # due within 3 days
        except (ValueError, TypeError):
            pass

    return round(max(0.01, min(1.0, base)), 4)

def complete_task(store: Store, task_id: str) -> dict | None:
    """Mark a task as done."""
    node = store.get_node(task_id)
    if not node or node.get("type") != "task":
        return None

    extra = node.get("extra") or {}
    extra["task_status"] = "done"
    extra["completed_at"] = _now()

    store.update_node(task_id, status="archived", extra=extra, weight=0.01)
    return store.get_node(task_id)

def cancel_task(store: Store, task_id: str) -> dict | None:
    """Cancel a task."""
    node = store.get_node(task_id)
    if not node or node.get("type") != "task":
        return None

    extra = node.get("extra") or {}
    extra["task_status"] = "cancelled"

    store.update_node(task_id, status="archived", extra=extra, weight=0.01)
    return store.get_node(task_id)

def update_task(store: Store, task_id: str, **fields) -> dict | None:
    """Update task-specific fields: priority, task_status, due, effort, scope."""
    node = store.get_node(task_id)
    if not node or node.get("type") != "task":
        return None

    extra = node.get("extra") or {}
    node_updates = {}

    if "priority" in fields:
        extra["priority"] = _parse_priority(fields["priority"])
    if "task_status" in fields and fields["task_status"] in VALID_STATUSES:
        extra["task_status"] = fields["task_status"]
        if fields["task_status"] == "done":
            extra["completed_at"] = _now()
            node_updates["status"] = "archived"
    if "due" in fields:
        extra["due"] = fields["due"]
    if "effort" in fields:
        extra["effort"] = fields["effort"]
    if "scope" in fields and fields["scope"] in VALID_SCOPES:
        extra["scope"] = fields["scope"]

    # Recalculate weight
    weight = compute_task_weight(extra.get("priority", 3), extra.get("due"))
    if extra.get("task_status") in ("done", "cancelled"):
        weight = 0.01

    node_updates["extra"] = extra
    node_updates["weight"] = weight
    store.update_node(task_id, **node_updates)
    return store.get_node(task_id)

def list_tasks(
    store: Store,
    *,
    status: str = "open",
    scope: str | None = None,
    domain: str | None = None,
    project_path: str | None = None,
    limit: int = 20,
) -> list[dict]:
    """List tasks with filters. Returns sorted by weight DESC, then due date."""
    node_status = "active" if status in ("open", "in_progress") else None
    if status == "all":
        node_status = None
    tasks = store.all_nodes(node_type="task", status=node_status, limit=500)

    result = []
    for t in tasks:
        extra = t.get("extra") or {}
        ts = extra.get("task_status", "open")

        # Status filter
        if status != "all" and ts != status:
            continue

        # Scope filter
        if scope and extra.get("scope") != scope:
            continue

        # Domain filter
        if domain:
            node_domains = t.get("domains") or []
            if domain.lower() not in [d.lower() for d in node_domains]:
                continue

        # Project path filter
        if project_path and extra.get("project_path"):
            if not project_path.startswith(extra["project_path"]):
                continue

        result.append(t)

    # Sort: weight DESC, then due date ASC (None last)
    def sort_key(t):
        extra = t.get("extra") or {}
        due = extra.get("due", "9999")
        return (-t.get("weight", 0), due)

    result.sort(key=sort_key)
    return result[:limit]

def format_task(task: dict) -> str:
    """Format a single task for display."""
    extra = task.get("extra") or {}
    pri = extra.get("priority", 3)
    p_label = PRIORITY_LABELS.get(pri, "normal")
    ts = extra.get("task_status", "open")
    due = extra.get("due", "")
    effort = extra.get("effort", "")
    scope = extra.get("scope", "contextual")

    lines = [
        f"  {task.get('id', '?')}: {task.get('title', '?')} ({ts})",
        f"    Priority: {p_label} ({pri})  |  Scope: {scope}  |  Weight: {task.get('weight', 0):.2f}",
    ]
    if due:
        lines.append(f"    Due: {due}")
    if effort:
        lines.append(f"    Effort: {effort}")
    if task.get("content"):
        lines.append(f"    Notes: {task['content'][:120]}")
    return "\n".join(lines)

def sort_key(t):
    extra = t.get("extra") or {}
    due = extra.get("due", "9999")
    return (-t.get("weight", 0), due)

def parse_frontmatter(filepath: Path) -> tuple[dict, str]:
    """Extract YAML frontmatter from a markdown file.

    Returns (meta_dict, body_text). Handles no-frontmatter, CRLF, bad YAML.
    """
    content = filepath.read_text(encoding="utf-8").replace("\r\n", "\n")

    if not content.startswith("---"):
        return {}, content

    parts = content.split("---", 2)
    if len(parts) < 3:
        return {}, content

    try:
        meta = yaml.safe_load(parts[1])
        return meta or {}, parts[2].strip()
    except yaml.YAMLError:
        return {}, content

def __init__(self, config: Config | None = None, config_path: str | None = None):
    self.config = config or load_config(config_path)
    self.topics: dict[str, TopicNode] = {}
    self.skills: dict[str, SkillNode] = {}
    self.forward: dict[str, list[Edge]] = defaultdict(list)
    self.reverse: dict[str, list[tuple[str, Edge]]] = defaultdict(list)

def ensure_dirs(self) -> None:
    """Create data directories if they don't exist."""
    for d in [self.config.topics_dir, self.config.skills_dir,
              self.config.inbox_dir, self.config.tmp_dir]:
        d.mkdir(parents=True, exist_ok=True)

def _load_topics(self) -> None:
    td = self.config.topics_dir
    if not td.exists():
        return
    for f in sorted(td.glob("*.md")):
        slug = f.stem
        meta, body = parse_frontmatter(f)
        node = TopicNode(slug=slug, path=f, body=body, **meta)
        node._has_frontmatter = bool(meta)
        if not node.topic:
            node.topic = slug
        self.topics[slug] = node

def _load_skills(self) -> None:
    sd = self.config.skills_dir
    if not sd.exists():
        return
    for f in sorted(sd.glob("*.md")):
        slug = f.stem
        meta, body = parse_frontmatter(f)
        node = SkillNode(slug=slug, path=f, body=body, **meta)
        if not node.skill:
            node.skill = slug
        self.skills[slug] = node

def _build_indexes(self) -> None:
    for slug, node in self.topics.items():
        for edge in node.connects_to:
            self.forward[slug].append(edge)
            self.reverse[edge.target].append((slug, edge))
    for slug, node in self.skills.items():
        for edge in node.connects_to:
            self.forward[slug].append(edge)
            self.reverse[edge.target].append((slug, edge))

def _atomic_write(self, path: Path, content: str) -> None:
    """Write to tmp, then os.replace() for crash safety."""
    self.config.tmp_dir.mkdir(parents=True, exist_ok=True)
    fd, tmp_path = tempfile.mkstemp(dir=self.config.tmp_dir, suffix=".md")
    try:
        os.write(fd, content.encode("utf-8"))
        os.close(fd)
        os.replace(tmp_path, path)
    except Exception:
        try:
            os.close(fd)
        except OSError:
            pass
        if os.path.exists(tmp_path):
            os.unlink(tmp_path)
        raise

def save_topic(self, node: TopicNode) -> None:
    if node.path is None:
        node.path = self.config.topics_dir / f"{node.slug}.md"
    content = serialize_frontmatter(node.frontmatter_dict(), node.body)
    self._atomic_write(node.path, content)

def save_skill(self, node: SkillNode) -> None:
    if node.path is None:
        node.path = self.config.skills_dir / f"{node.slug}.md"
    content = serialize_frontmatter(node.frontmatter_dict(), node.body)
    self._atomic_write(node.path, content)

def add_edge(self, source: str, target: str, weight: float, reason: str) -> None:
    node = self.get(source)
    if node is None:
        raise KeyError(f"Node '{source}' not found")

    existing = node.edge_to(target) if hasattr(node, "edge_to") else None
    if existing:
        existing.weight = weight
        existing.reason = reason
    else:
        edge = Edge(target=target, weight=weight, reason=reason)
        node.connects_to.append(edge)
        self.forward[source].append(edge)
        self.reverse[target].append((source, edge))

    if isinstance(node, TopicNode):
        self.save_topic(node)
    else:
        self.save_skill(node)

def _check_vec() -> bool:
    """Check if sqlite-vec extension is available."""
    global _VEC_AVAILABLE
    if _VEC_AVAILABLE is not None:
        return _VEC_AVAILABLE
    try:
        import sqlite_vec  # noqa: F401
        _VEC_AVAILABLE = True
    except ImportError:
        _VEC_AVAILABLE = False
    return _VEC_AVAILABLE

def _get_model():
    """Lazy-load the sentence transformer model."""
    global _MODEL
    if _MODEL is not None:
        return _MODEL
    try:
        from sentence_transformers import SentenceTransformer
        _MODEL = SentenceTransformer("all-MiniLM-L6-v2")
        return _MODEL
    except ImportError:
        print("Warning: sentence-transformers not installed. "
              "Install with: pip install sentence-transformers", file=sys.stderr)
        return None

def is_available() -> bool:
    """Check if vector search is available."""
    return _check_vec()

def embed_text(text: str) -> list[float] | None:
    """Embed a text string into a vector."""
    model = _get_model()
    if model is None:
        return None
    embedding = model.encode(text, normalize_embeddings=True)
    return embedding.tolist()

def upsert_embedding(store: Store, node_id: str, text: str) -> bool:
    """Compute and store an embedding for a node."""
    embedding = embed_text(text)
    if embedding is None:
        return False

    try:
        store.conn.execute(
            "INSERT OR REPLACE INTO node_vectors (node_id, embedding) VALUES (?, ?)",
            (node_id, _serialize_vec(embedding)),
        )
        store.conn.commit()
        return True
    except Exception:
        return False

def vector_search(store: Store, query: str, top_k: int = 10) -> list[dict]:
    """Search for similar nodes using vector similarity."""
    if not _check_vec():
        return []

    embedding = embed_text(query)
    if embedding is None:
        return []

    try:
        rows = store.conn.execute(
            """SELECT node_id, distance
               FROM node_vectors
               WHERE embedding MATCH ?
               ORDER BY distance
               LIMIT ?""",
            (_serialize_vec(embedding), top_k),
        ).fetchall()

        results = []
        for row in rows:
            node = store.get_node(row[0])
            if node:
                node["vec_distance"] = row[1]
                results.append(node)
        return results
    except Exception:
        return []

def _serialize_vec(embedding: list[float]) -> bytes:
    """Serialize a float list to bytes for sqlite-vec."""
    import struct
    return struct.pack(f"{len(embedding)}f", *embedding)

def index_all_nodes(store: Store, verbose: bool = False) -> int:
    """Index all nodes that don't have embeddings yet."""
    if not ensure_vec_table(store):
        print("Vector search not available. Install: pip install sqlite-vec sentence-transformers",
              file=sys.stderr)
        return 0

    nodes = store.all_nodes(limit=10000)
    count = 0
    for node in nodes:
        text = f"{node['title']} {(node.get('content') or '')[:1000]}"
        if upsert_embedding(store, node["id"], text):
            count += 1
            if verbose:
                print(f"  Embedded: {node['title']}")

    return count

