def is_linear_available() -> bool:
    """Check if Linear API key is available."""
    return bool(os.environ.get("LINEAR_API_KEY"))

def _linear_query(query: str, variables: dict | None = None) -> dict | None:
    """Execute a Linear GraphQL query."""
    api_key = os.environ.get("LINEAR_API_KEY")
    if not api_key:
        return None

    payload = json.dumps({"query": query, "variables": variables or {}})

    try:
        result = subprocess.run(
            ["curl", "-s", "-X", "POST",
             "https://api.linear.app/graphql",
             "-H", "Content-Type: application/json",
             "-H", f"Authorization: {api_key}",
             "-d", payload],
            capture_output=True, text=True, timeout=30,
        )
        if result.returncode == 0:
            return json.loads(result.stdout)
    except Exception:
        pass
    return None

def ingest_issues(store: "Store", team: str | None = None,
                  limit: int = 50, verbose: bool = False) -> int:
    """Ingest Linear issues as knowledge nodes."""

    query = """
    query($first: Int, $filter: IssueFilter) {
        issues(first: $first, filter: $filter, orderBy: updatedAt) {
            nodes {
                id
                identifier
                title
                description
                state { name }
                labels { nodes { name } }
                assignee { name }
                createdAt
                updatedAt
                url
                project { name }
            }
        }
    }
    """

    variables = {"first": limit}
    if team:
        variables["filter"] = {"team": {"key": {"eq": team}}}

    data = _linear_query(query, variables)
    if not data or "data" not in data:
        return 0

    issues = data["data"].get("issues", {}).get("nodes", [])
    count = 0

    for issue in issues:
        node_id = f"linear-{issue['identifier']}"

        if store.get_node(node_id):
            continue

        title = f"{issue['identifier']}: {issue['title']}"
        body = (issue.get("description") or "")[:2000]
        labels = [l["name"] for l in issue.get("labels", {}).get("nodes", [])]
        assignee = (issue.get("assignee") or {}).get("name", "")
        state = (issue.get("state") or {}).get("name", "")
        project = (issue.get("project") or {}).get("name", "")

        status = "active"
        if state.lower() in ("done", "closed", "cancelled", "canceled"):
            status = "archived"

        domains = ["linear"] + labels
        if project:
            domains.append(project.lower().replace(" ", "-"))

        store.add_node(
            node_id=node_id,
            title=title,
            content=body,
            node_type="document",
            domains=domains,
            status=status,
            prov_who=[assignee.lower().replace(" ", "-")] if assignee else [],
            prov_source=issue.get("url", ""),
            prov_activity="linear-ingest",
            extra={"identifier": issue["identifier"], "state": state,
                   "project": project, "labels": labels},
        )
        count += 1
        if verbose:
            print(f"  Linear: {title}")

    return count

def ingest(self, store, *, limit=50, since=None, verbose=False, **kwargs):
    team = kwargs.get("team")
    created = ingest_issues(store, team=team, limit=limit, verbose=verbose)
    return IngestResult(created=created)

def run_adapter(
    adapter: Adapter,
    store: Store,
    config: IngestConfig | None = None,
    **kwargs: Any,
) -> IngestResult:
    """Execute an adapter with shared pipeline wrapping.

    1. Check availability
    2. Run the adapter's ingest() method
    3. Report results

    Args:
        adapter: The adapter to run.
        store: Kindex Store instance.
        config: Shared ingestion configuration.
        **kwargs: Adapter-specific options (repo, team, path, etc.).

    Returns:
        IngestResult with created/updated/skipped/error counts.
    """
    if config is None:
        config = IngestConfig()

    name = adapter.meta.name

    # Check prerequisites
    if not adapter.is_available():
        hint = adapter.meta.auth_hint or "prerequisites not met"
        msg = f"{name}: not available ({hint})"
        if config.verbose:
            print(msg, file=sys.stderr)
        return IngestResult(errors=[msg])

    if config.dry_run:
        if config.verbose:
            print(f"[dry-run] Would run adapter: {name}")
        return IngestResult()

    if config.verbose:
        print(f"Ingesting from {name}...")

    # Run the adapter
    try:
        result = adapter.ingest(
            store,
            limit=config.limit,
            since=config.since,
            verbose=config.verbose,
            **kwargs,
        )
    except Exception as e:
        msg = f"{name}: {type(e).__name__}: {e}"
        if config.verbose:
            print(f"  Error: {msg}", file=sys.stderr)
        return IngestResult(errors=[msg])

    if config.verbose:
        print(f"  {name}: {result}")

    return result

def run_all(
    store: Store,
    config: IngestConfig | None = None,
    **kwargs: Any,
) -> dict[str, IngestResult]:
    """Run all available adapters and return per-adapter results."""
    from .registry import discover

    if config is None:
        config = IngestConfig()

    results: dict[str, IngestResult] = {}
    for name, adapter in sorted(discover().items()):
        if adapter.is_available():
            results[name] = run_adapter(adapter, store, config, **kwargs)

    return results

def discover() -> dict[str, Adapter]:
    """Return all adapters: built-in + entry-point discovered.

    Results are cached after first call. Use ``reset()`` to clear.
    """
    global _cache
    if _cache is not None:
        return dict(_cache)

    adapters = dict(_BUILTIN)

    # Discover third-party adapters via entry points
    try:
        eps = entry_points(group=EP_GROUP)
    except TypeError:
        # Python < 3.12 fallback
        eps = entry_points().get(EP_GROUP, [])  # type: ignore[arg-type]

    for ep in eps:
        if ep.name in adapters:
            continue  # built-in takes precedence
        try:
            obj = ep.load()
            # Accept either an Adapter instance or a module with .adapter attr
            if hasattr(obj, "meta") and hasattr(obj, "ingest"):
                adapters[ep.name] = obj
            elif hasattr(obj, "adapter"):
                adapters[ep.name] = obj.adapter
            else:
                log.warning("Entry point %s does not expose an Adapter", ep.name)
        except Exception:
            log.warning("Failed to load adapter entry point: %s", ep.name, exc_info=True)

    _cache = adapters
    return dict(adapters)

def get(name: str) -> Adapter | None:
    """Get a specific adapter by name."""
    return discover().get(name)

def available() -> dict[str, Adapter]:
    """Return only adapters whose prerequisites are met."""
    return {k: v for k, v in discover().items() if v.is_available()}

def _register_builtins() -> None:
    """Register all built-in adapters. Called once at import time."""
    # Lazy imports to avoid circular dependencies and heavy imports at startup
    try:
        from .github import adapter as github
        register(github)
    except Exception:
        pass

    try:
        from .linear import adapter as linear
        register(linear)
    except Exception:
        pass

    try:
        from .git_hooks import adapter as commits
        register(commits)
    except Exception:
        pass

    try:
        from .files import adapter as files
        register(files)
    except Exception:
        pass

    try:
        from .projects import adapter as projects
        register(projects)
    except Exception:
        pass

    try:
        from .sessions import adapter as sessions
        register(sessions)
    except Exception:
        pass

    try:
        from .claude_web import adapter as claude_web
        register(claude_web)
    except Exception:
        pass

def is_available(self) -> bool:
    from pathlib import Path

    return Path("~/.claude").expanduser().exists()

def ingest(self, store, *, limit=50, since=None, verbose=False, **kwargs):
    from ..config import load_config
    from ..ingest import scan_sessions

    cfg = kwargs.get("_config") or load_config()
    created = scan_sessions(cfg, store, limit=limit, verbose=verbose)
    return IngestResult(created=created)
